// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import java.io.File;
import java.nio.ByteBuffer;
import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.TxnManager.Txn;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Storage-level tests for {@link TripleStore#getTriplesRange}: pattern scans constrained to a raw key subrange
 * ({@code lowKey} inclusive, {@code highKeyExclusive} exclusive) of the pattern's index, the building block for
 * range-partitioned parallel root scans.
 */
public class LmdbRecordIteratorRangeBoundsTest {

	@TempDir
	File dataDir;

	private TripleStore tripleStore;

	@BeforeEach
	public void setUp() throws Exception {
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc,posc"), null);
		tripleStore.startTransaction();
		for (long subj = 100; subj < 110; subj++) {
			// posc keys: (10, 1000+subj, subj, 1); objects 1100..1109 ascending
			tripleStore.storeTriple(subj, 10, 1000 + subj, 1, true);
		}
		tripleStore.commit();
	}

	/** Raw posc index key for one quad, matching {@link TripleIndex#toKey} field order. */
	private static byte[] poscKey(long pred, long obj, long subj, long context) {
		ByteBuffer bb = ByteBuffer.allocate(TripleIndex.MAX_KEY_LENGTH);
		Varint.writeListUnsigned(bb, new long[] { pred, obj, subj, context });
		bb.flip();
		byte[] key = new byte[bb.remaining()];
		bb.get(key);
		return key;
	}

	private LmdbKeyRange range(byte[] low, byte[] high) {
		return new LmdbKeyRange(low, high, tripleStore.getIndexName(-1, 10, -1, -1));
	}

	private List<Long> scanObjects(Txn txn, LmdbKeyRange range) throws Exception {
		List<Long> objects = new ArrayList<>();
		try (RecordIterator iterator = tripleStore.getTriplesRange(txn, -1, 10, -1, -1, true, range)) {
			long[] quad;
			while ((quad = iterator.next()) != null) {
				objects.add(quad[TripleIndex.OBJ_IDX]);
			}
		}
		return objects;
	}

	@Test
	public void boundsInsidePrefixSubrangeClampBothEnds() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			// low bound before object 1103's group, high bound before object 1107's group
			List<Long> objects = scanObjects(txn, range(poscKey(10, 1103, 0, 0), poscKey(10, 1107, 0, 0)));
			assertThat(objects).containsExactly(1103L, 1104L, 1105L, 1106L);
		}
	}

	@Test
	public void upperBoundIsExclusiveOnExactKeyMatch() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			// the exact stored key of object 1106 as the exclusive upper bound: 1106 must be excluded
			List<Long> objects = scanObjects(txn, range(poscKey(10, 1103, 0, 0), poscKey(10, 1106, 106, 1)));
			assertThat(objects).containsExactly(1103L, 1104L, 1105L);
		}
	}

	@Test
	public void splitKeyAppearsOnlyInRightPartition() throws Exception {
		byte[] split = poscKey(10, 1105, 105, 1); // exact key of an existing quad
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			List<Long> left = scanObjects(txn, range(null, split));
			List<Long> right = scanObjects(txn, range(split, null));
			assertThat(left).containsExactly(1100L, 1101L, 1102L, 1103L, 1104L);
			assertThat(right).containsExactly(1105L, 1106L, 1107L, 1108L, 1109L);
		}
	}

	@Test
	public void partitionConcatenationEqualsFullScan() throws Exception {
		byte[] split1 = poscKey(10, 1103, 0, 0);
		byte[] split2 = poscKey(10, 1107, 107, 1); // one synthetic, one exact split key
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			List<Long> concatenated = new ArrayList<>();
			concatenated.addAll(scanObjects(txn, range(null, split1)));
			concatenated.addAll(scanObjects(txn, range(split1, split2)));
			concatenated.addAll(scanObjects(txn, range(split2, null)));

			List<Long> full = new ArrayList<>();
			try (RecordIterator iterator = tripleStore.getTriples(txn, -1, 10, -1, -1, true)) {
				long[] quad;
				while ((quad = iterator.next()) != null) {
					full.add(quad[TripleIndex.OBJ_IDX]);
				}
			}
			assertThat(concatenated).containsExactlyElementsOf(full);
		}
	}

	@Test
	public void skipScanRunsTerminateAtUpperBound() throws Exception {
		// long run of context-2 quads after the context-1 block: matching on context 1 forces KEY_FILTERED runs
		// that trigger skip-scan seeks, which may overshoot the bound and must still terminate cleanly
		tripleStore.startTransaction();
		for (long obj = 2000; obj < 2040; obj++) {
			tripleStore.storeTriple(500, 10, obj, 2, true);
		}
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			byte[] high = poscKey(10, 2010, 0, 0); // inside the context-2 run
			List<Long> objects = new ArrayList<>();
			try (RecordIterator iterator = tripleStore.getTriplesRange(txn, -1, 10, -1, 1, true,
					new LmdbKeyRange(null, high, tripleStore.getIndexName(-1, 10, -1, 1)))) {
				long[] quad;
				while ((quad = iterator.next()) != null) {
					objects.add(quad[TripleIndex.OBJ_IDX]);
				}
			}
			assertThat(objects).containsExactly(1100L, 1101L, 1102L, 1103L, 1104L, 1105L, 1106L, 1107L, 1108L, 1109L);
		}
	}

	@Test
	public void seekForwardStaysWithinUpperBound() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			byte[] high = poscKey(10, 1108, 108, 1); // exact key of 1108, exclusive
			try (RecordIterator iterator = tripleStore.getTriplesRange(txn, -1, 10, -1, -1, true,
					range(null, high))) {
				assertThat(iterator.next()[TripleIndex.OBJ_IDX]).isEqualTo(1100L);
				assertThat(iterator.seekForward(0, 10, 1106, 0)).isTrue();
				assertThat(iterator.next()[TripleIndex.OBJ_IDX]).isEqualTo(1106L);
				assertThat(iterator.next()[TripleIndex.OBJ_IDX]).isEqualTo(1107L);
				assertThat(iterator.next()).isNull();
			}
		}
	}

	@Test
	public void boundsComposeWithFillBatches() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			try (RecordIterator iterator = tripleStore.getTriplesRange(txn, -1, 10, -1, -1, true,
					range(poscKey(10, 1102, 0, 0), poscKey(10, 1108, 0, 0)))) {
				long[] buffer = new long[4 * 4];
				assertThat(iterator.fill(buffer, 4)).isEqualTo(4);
				assertThat(buffer[TripleIndex.OBJ_IDX]).isEqualTo(1102L);
				assertThat(iterator.fill(buffer, 4)).isEqualTo(2);
				assertThat(buffer[TripleIndex.OBJ_IDX]).isEqualTo(1106L);
				assertThat(buffer[4 + TripleIndex.OBJ_IDX]).isEqualTo(1107L);
			}
		}
	}

	@Test
	public void boundsSurviveTransactionVersionRenew() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			try (RecordIterator iterator = tripleStore.getTriplesRange(txn, -1, 10, -1, -1, true,
					range(null, poscKey(10, 1107, 0, 0)))) {
				assertThat(iterator.next()[TripleIndex.OBJ_IDX]).isEqualTo(1100L);
				assertThat(iterator.next()[TripleIndex.OBJ_IDX]).isEqualTo(1101L);

				// a committed write bumps the tracked read txn's version; the iterator must renew its cursor,
				// reposition after the last handed-out key, and keep enforcing the injected upper bound
				tripleStore.startTransaction();
				tripleStore.storeTriple(200, 10, 1200, 1, true); // beyond the bound: must never appear
				tripleStore.storeTriple(90, 10, 1103, 3, true); // inside the bound: new key in-range
				tripleStore.commit();

				List<Long> rest = new ArrayList<>();
				long[] quad;
				while ((quad = iterator.next()) != null) {
					rest.add(quad[TripleIndex.OBJ_IDX]);
				}
				assertThat(rest).containsExactly(1102L, 1103L, 1103L, 1104L, 1105L, 1106L);
			}
		}
	}

	@Test
	public void mismatchedIndexIsRejected() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			LmdbKeyRange wrongIndex = new LmdbKeyRange(null, poscKey(10, 1105, 0, 0), "cspo");
			assertThatThrownBy(() -> tripleStore.getTriplesRange(txn, -1, 10, -1, -1, true, wrongIndex))
					.isInstanceOf(IllegalStateException.class)
					.hasMessageContaining("cspo");
		}
	}
}
